/**
 * Notification log model for tracking sent notification history.
 *
 * Each log entry captures the result of a notification dispatch attempt,
 * including recipient, channel, type, delivery status, and timestamp.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

/** Delivery status of a notification. */
export type DeliveryStatus = 'delivered' | 'failed';

/**
 * A persistent log entry for a dispatched notification.
 */
export interface NotificationLog {
  /** Unique log entry ID. */
  id: string;
  /** ID of the original notification payload. */
  notificationId: string;
  /** Recipient (email address or user identifier). */
  recipient: string;
  /** Delivery channel used. */
  channel: NotificationChannel;
  /** Notification type. */
  type: NotificationType;
  /** Notification subject/title. */
  subject: string;
  /** Whether the notification was delivered or failed. */
  status: DeliveryStatus;
  /** Error message if delivery failed. */
  error?: string;
  /** Metadata from the original notification payload. */
  metadata: Record<string, string>;
  /** When the notification was sent/attempted. */
  sentAt: Date;
  /** When this log entry was created. */
  createdAt: Date;
}

/**
 * Filter criteria for querying notification history.
 */
export interface NotificationLogFilter {
  /** Filter by recipient. */
  recipient?: string;
  /** Filter by notification type. */
  type?: NotificationType;
  /** Filter by delivery channel. */
  channel?: NotificationChannel;
  /** Filter by delivery status. */
  status?: DeliveryStatus;
  /** Only include logs sent on or after this date. */
  startDate?: Date;
  /** Only include logs sent on or before this date. */
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods
 * for filtering by recipient, type, channel, and date range.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog } from '../models/notification-log.js';
import type { NotificationLogFilter } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationLog['channel'],
      type: record['type'] as NotificationLog['type'],
      subject: record['subject'] as string,
      status: record['status'] as NotificationLog['status'],
      error: record['error'] as string | undefined,
      metadata: JSON.parse(record['metadata'] as string),
      sentAt: new Date(record['sentAt'] as string),
      createdAt: new Date(record['createdAt'] as string),
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      subject: entity.subject,
      status: entity.status,
      error: entity.error,
      metadata: JSON.stringify(entity.metadata),
      sentAt: entity.sentAt.toISOString(),
      createdAt: entity.createdAt.toISOString(),
    };
  }

  /**
   * Find all logs matching the given filter criteria.
   */
  findByFilter(filter: NotificationLogFilter): NotificationLog[] {
    return this.findAll((log) => {
      if (filter.recipient && log.recipient !== filter.recipient) return false;
      if (filter.type && log.type !== filter.type) return false;
      if (filter.channel && log.channel !== filter.channel) return false;
      if (filter.status && log.status !== filter.status) return false;
      if (filter.startDate && log.sentAt < filter.startDate) return false;
      if (filter.endDate && log.sentAt > filter.endDate) return false;
      return true;
    });
  }

  /**
   * Find all logs for a specific recipient.
   */
  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }
}

/**
 * Notification history service — logs and queries sent notification history.
 *
 * Every notification dispatched through the NotificationService is logged
 * here for auditing and querying. The history captures recipient, channel,
 * type, timestamp, and delivery status.
 *
 * Depends on:
 * - NotificationLogRepository for persistence
 */

import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import type { NotificationLog, NotificationLogFilter } from '../models/notification-log.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateLogId(): string {
  return `log-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (for testing). */
export function resetLogIdCounter(): void {
  nextId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Log a notification dispatch result. Called by NotificationService after
   * each send attempt (success or failure).
   */
  log(payload: NotificationPayload, result: NotificationResult): NotificationLog {
    const entry: NotificationLog = {
      id: generateLogId(),
      notificationId: payload.id,
      recipient: payload.recipient,
      channel: payload.channel,
      type: payload.type,
      subject: payload.subject,
      status: result.success ? 'delivered' : 'failed',
      error: result.error,
      metadata: payload.metadata,
      sentAt: result.deliveredAt,
      createdAt: new Date(),
    };

    this.repository.save(entry);
    this.logger.info(
      `Logged notification ${payload.id}: ${entry.status} via ${entry.channel} to ${entry.recipient}`,
    );
    return entry;
  }

  /**
   * Query notification history with flexible filters.
   */
  query(filter: NotificationLogFilter): NotificationLog[] {
    return this.repository.findByFilter(filter);
  }

  /**
   * Get all notification logs for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all notification logs of a specific type.
   */
  getByType(type: NotificationLog['type']): NotificationLog[] {
    return this.repository.findByFilter({ type });
  }

  /**
   * Get all notification logs within a date range.
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.repository.findByFilter({ startDate, endDate });
  }

  /**
   * Get a single log entry by ID.
   */
  getById(id: string): NotificationLog | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get the total count of logged notifications.
   */
  count(): number {
    return this.repository.count();
  }
}

