import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { NotificationPayload, NotificationResult } from '../../src/models/notification.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
    return {
      id: 'notif-0001',
      type: 'order_confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Order Confirmation: order-1',
      body: 'Your order has been placed.',
      priority: 'normal',
      metadata: { orderId: 'order-1', userId: 'user-1' },
      createdAt: new Date('2026-01-15T10:00:00Z'),
      ...overrides,
    };
  }

  function makeResult(overrides: Partial<NotificationResult> = {}): NotificationResult {
    return {
      success: true,
      channel: 'email',
      deliveredAt: new Date('2026-01-15T10:00:01Z'),
      ...overrides,
    };
  }

  describe('log', () => {
    it('should create a log entry for a successful notification', () => {
      const payload = makePayload();
      const result = makeResult();

      const log = historyService.log(payload, result);

      expect(log.id).toBe('log-0001');
      expect(log.notificationId).toBe('notif-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.channel).toBe('email');
      expect(log.type).toBe('order_confirmation');
      expect(log.subject).toBe('Order Confirmation: order-1');
      expect(log.status).toBe('delivered');
      expect(log.error).toBeUndefined();
      expect(log.metadata).toEqual({ orderId: 'order-1', userId: 'user-1' });
      expect(log.sentAt).toEqual(new Date('2026-01-15T10:00:01Z'));
    });

    it('should create a log entry for a failed notification', () => {
      const payload = makePayload();
      const result = makeResult({ success: false, error: 'Transport error' });

      const log = historyService.log(payload, result);

      expect(log.status).toBe('failed');
      expect(log.error).toBe('Transport error');
    });

    it('should generate sequential log IDs', () => {
      const payload1 = makePayload({ id: 'notif-0001' });
      const payload2 = makePayload({ id: 'notif-0002' });
      const result = makeResult();

      const log1 = historyService.log(payload1, result);
      const log2 = historyService.log(payload2, result);

      expect(log1.id).toBe('log-0001');
      expect(log2.id).toBe('log-0002');
    });

    it('should persist log entries to the repository', () => {
      historyService.log(makePayload(), makeResult());

      expect(repository.count()).toBe(1);
      const stored = repository.findById('log-0001');
      expect(stored).toBeDefined();
      expect(stored!.notificationId).toBe('notif-0001');
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.log(
        makePayload({ id: 'notif-0001', recipient: 'alice@example.com', type: 'order_confirmation', channel: 'email' }),
        makeResult({ deliveredAt: new Date('2026-01-15T10:00:00Z') }),
      );
      historyService.log(
        makePayload({ id: 'notif-0002', recipient: 'bob@example.com', type: 'welcome', channel: 'email' }),
        makeResult({ deliveredAt: new Date('2026-01-16T10:00:00Z') }),
      );
      historyService.log(
        makePayload({ id: 'notif-0003', recipient: 'alice@example.com', type: 'order_status_update', channel: 'webhook' }),
        makeResult({ success: false, error: 'Timeout', channel: 'webhook', deliveredAt: new Date('2026-01-17T10:00:00Z') }),
      );
    });

    it('should filter by recipient', () => {
      const logs = historyService.query({ recipient: 'alice@example.com' });
      expect(logs).toHaveLength(2);
      expect(logs.every((l) => l.recipient === 'alice@example.com')).toBe(true);
    });

    it('should filter by type', () => {
      const logs = historyService.query({ type: 'welcome' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.type).toBe('welcome');
    });

    it('should filter by channel', () => {
      const logs = historyService.query({ channel: 'webhook' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.channel).toBe('webhook');
    });

    it('should filter by status', () => {
      const logs = historyService.query({ status: 'failed' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('failed');
      expect(logs[0]!.error).toBe('Timeout');
    });

    it('should filter by date range', () => {
      const logs = historyService.query({
        startDate: new Date('2026-01-16T00:00:00Z'),
        endDate: new Date('2026-01-16T23:59:59Z'),
      });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.recipient).toBe('bob@example.com');
    });

    it('should combine multiple filters', () => {
      const logs = historyService.query({
        recipient: 'alice@example.com',
        status: 'delivered',
      });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.type).toBe('order_confirmation');
    });

    it('should return empty array when no matches', () => {
      const logs = historyService.query({ recipient: 'nobody@example.com' });
      expect(logs).toHaveLength(0);
    });

    it('should return all logs with empty filter', () => {
      const logs = historyService.query({});
      expect(logs).toHaveLength(3);
    });
  });

  describe('getByRecipient', () => {
    it('should return logs for a specific recipient', () => {
      historyService.log(makePayload({ recipient: 'alice@example.com' }), makeResult());
      historyService.log(makePayload({ recipient: 'bob@example.com' }), makeResult());

      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.recipient).toBe('alice@example.com');
    });
  });

  describe('getByType', () => {
    it('should return logs for a specific type', () => {
      historyService.log(makePayload({ type: 'order_confirmation' }), makeResult());
      historyService.log(makePayload({ type: 'welcome' }), makeResult());

      const logs = historyService.getByType('welcome');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.type).toBe('welcome');
    });
  });

  describe('getByDateRange', () => {
    it('should return logs within the date range', () => {
      historyService.log(makePayload(), makeResult({ deliveredAt: new Date('2026-01-10T10:00:00Z') }));
      historyService.log(makePayload(), makeResult({ deliveredAt: new Date('2026-01-20T10:00:00Z') }));
      historyService.log(makePayload(), makeResult({ deliveredAt: new Date('2026-01-30T10:00:00Z') }));

      const logs = historyService.getByDateRange(
        new Date('2026-01-15T00:00:00Z'),
        new Date('2026-01-25T00:00:00Z'),
      );
      expect(logs).toHaveLength(1);
      expect(logs[0]!.sentAt).toEqual(new Date('2026-01-20T10:00:00Z'));
    });
  });

  describe('getById', () => {
    it('should return a log entry by ID', () => {
      historyService.log(makePayload(), makeResult());

      const log = historyService.getById('log-0001');
      expect(log).toBeDefined();
      expect(log!.notificationId).toBe('notif-0001');
    });

    it('should return undefined for unknown ID', () => {
      expect(historyService.getById('log-9999')).toBeUndefined();
    });
  });

  describe('count', () => {
    it('should return 0 when no logs exist', () => {
      expect(historyService.count()).toBe(0);
    });

    it('should return the number of logged entries', () => {
      historyService.log(makePayload(), makeResult());
      historyService.log(makePayload({ id: 'notif-0002' }), makeResult());
      expect(historyService.count()).toBe(2);
    });
  });
});

